import { useState } from 'react';
import './Home.css'
import { useSearchParams } from 'react-router-dom';
function Home (){
    const [title,setTitle] = useState('') // for title of paste 
    const [value,setValue] = useState('') // for content which we paste
    const [searchParams,setSearchParams] = useSearchParams(); // it allow to read and update query parameters
    const pasteID = searchParams.get('pasteID')
    return(
        <div id='Home'>
            <label style={{fontSize:'20px'}}>Title :</label>
            <input style={{borderRadius:'5px',height:"25px",marginLeft:'15px',borderRadius:'10px'}}
            type='text'
            placeholder='enter title here...'
            value={title}
            onChange={(e)=>setTitle(e.target.value)}
            />
            <button>Add my paste</button>
        </div>
    )
}
export default Home;
